--
-- Disparadores `tenants`
--
DELIMITER $$
CREATE TRIGGER `trg_tenants_prevent_system_delete` BEFORE DELETE ON `tenants` FOR EACH ROW BEGIN
    IF OLD.`is_system_tenant` = 1 THEN
        SIGNAL SQLSTATE '45000' 
        SET MESSAGE_TEXT = 'Cannot delete system tenant (is_system_tenant = TRUE). Use soft delete (is_active = 0).';
    END IF;
END
$$
DELIMITER ;

