-- Estructura para la vista `v_tenant_plan_limits`
--
DROP TABLE IF EXISTS `v_tenant_plan_limits`;

CREATE ALGORITHM=UNDEFINED DEFINER=`admkoda`@`localhost` SQL SECURITY INVOKER VIEW `v_tenant_plan_limits`  AS SELECT `t`.`tenant_id` AS `tenant_id`, `t`.`subscription_plan_id` AS `subscription_plan_id`, `pl`.`module` AS `module`, `pl`.`metric` AS `metric`, `pl`.`value` AS `limit_value`, coalesce(`u`.`current_value`,0) AS `current_usage`, CASE WHEN `pl`.`value` = 0 THEN 1 WHEN coalesce(`u`.`current_value`,0) < `pl`.`value` THEN 1 ELSE 0 END AS `has_capacity` FROM (((`tenants` `t` join `subscription_plans` `sp` on(`sp`.`id` = `t`.`subscription_plan_id`)) join `plan_limits` `pl` on(`pl`.`plan_id` = `sp`.`id`)) left join `tenant_plan_usage` `u` on(`u`.`tenant_id` = `t`.`tenant_id` and `u`.`module` = `pl`.`module` and `u`.`metric` = `pl`.`metric`)) WHERE `t`.`is_active` = 1 AND `sp`.`deleted_at` is null ;

